-- ================================
-- GIMPA Department Information for AI Knowledge Base
-- ================================

insert into public.ai_knowledge (source, section, content, tags) values
(
    'GIMPA-Departments',
    'GIMPA Business School Overview',
    'GIMPA Business School focuses on business administration, finance, marketing, and related disciplines. It offers undergraduate programs including BSc Business Administration with specializations in Accounting, Banking and Finance, Human Resource Management, Marketing, Operations and Project Management, and Entrepreneurship and Innovation. Postgraduate programs include MBA, Executive MBA, MSc Finance, MSc Energy Economics, and MSc Leadership. The Business School building is located on the main Greenhill campus.',
    array['departments', 'business school', 'gba', 'mba', 'finance', 'marketing', 'hr', 'undergraduate', 'postgraduate']
),
(
    'GIMPA-Departments',
    'School of Public Service and Governance Overview',
    'School of Public Service and Governance specializes in public administration, policy analysis, and governance studies. It offers BA Public Administration and BSc Economics and Political Science at undergraduate level. Postgraduate programs include MPA (Master of Public Administration), Master of Governance and Leadership, and Masters in International Relations and Diplomacy. These programs prepare students for careers in government, public service, policy analysis, and international affairs.',
    array['departments', 'public service', 'governance', 'public administration', 'mpa', 'international relations', 'undergraduate', 'postgraduate']
),
(
    'GIMPA-Departments',
    'Faculty of Law Overview',
    'Faculty of Law offers programs in legal education from undergraduate through postgraduate levels. Undergraduate program is the LLB (Bachelor of Laws). Postgraduate programs include LLM (Master of Laws) and Post-First Degree LLB. The Law Library is located on the top floor of the Law Faculty building. The faculty prepares students for legal practice and offers specialized legal studies at advanced levels.',
    array['departments', 'law', 'faculty of law', 'llb', 'llm', 'legal education', 'undergraduate', 'postgraduate']
),
(
    'GIMPA-Departments',
    'School of Technology Overview',
    'School of Technology provides education in information technology, computing, and digital innovations. Undergraduate programs include BSc Information Technology and BSc Computer Science. Postgraduate programs include MSc Information Technology, MSc Digital Forensics and Cybersecurity, and MSc ICT, IT & Law. Strong mathematics and technical background is important for these programs. The IT office is located in the School of Technology building.',
    array['departments', 'technology', 'school of technology', 'information technology', 'computer science', 'cybersecurity', 'undergraduate', 'postgraduate']
),
(
    'GIMPA-Departments',
    'School of Liberal Arts and Social Sciences Overview',
    'School of Liberal Arts and Social Sciences covers humanities, social sciences, and interdisciplinary studies. Undergraduate programs include BA Communication Studies and BA Political Science. Postgraduate programs include MA Political Science and MA Development Studies. These programs develop skills in communication, political analysis, and understanding social and political systems.',
    array['departments', 'liberal arts', 'social sciences', 'communication studies', 'political science', 'development studies', 'undergraduate', 'postgraduate']
),
(
    'GIMPA-Departments',
    'School of Research and Graduate Studies Overview',
    'School of Research and Graduate Studies oversees research activities and advanced postgraduate programs across all GIMPA academic schools. It manages PhD programs available in various disciplines and the Doctor of Management (DMGT) program. This school ensures research quality and provides support for graduate students pursuing advanced research degrees.',
    array['departments', 'research', 'graduate studies', 'phd', 'doctoral', 'dmgt', 'research support']
),
(
    'GIMPA-Departments',
    'Office of the Dean of Students (ODS)',
    'The Office of the Dean of Students is headed by the Acting Dean of Students, Prof. Augustina Akonnor. The ODS is mandated to promote student welfare in academic and social matters. It is located in the Student Affairs Building, adjacent the Consultancy Block, Number 2 Oval Street, PO Box AH 50, Achimota, Accra. Services include student complaints handling, internship coordination, pre-employment skills training, resume/CV writing workshops, career guidance, emotional support, and leadership development programmes.',
    array['departments', 'dean of students', 'student affairs', 'student welfare', 'ods', 'support services']
),
(
    'GIMPA-Departments',
    'GIMPA Counselling Unit (GCU)',
    'The GIMPA Counselling Unit provides confidential and professional mental health services to students experiencing emotional distress. Services include initial evaluations, individual counselling, group counselling, career counselling, consultations on mental health issues, psychoeducational workshops, and external referrals. To make an appointment: book online at http://scheduler.gimpa.edu.gh/ea/ or email gcu@gimpa.edu.gh. Both in-person and virtual appointments are available.',
    array['departments', 'counselling', 'mental health', 'gcu', 'student support', 'wellness']
),
(
    'GIMPA-Departments',
    'GIMPA Library System',
    'The GIMPA Library system includes Main Library (Lending and Reference) located at the apex of the Greenhill campus opposite CBG bank, Faculty of Law Library on top floor of Law Faculty building, and libraries at Kumasi, Tema, and Takoradi campuses. Library hours: Weekdays 8 AM-10 PM, Saturdays 8 AM-4 PM, closed on public holidays. During exam periods: Weekdays 8 AM-midnight, Saturday 8 AM-4 PM, Sunday 2 PM-8 PM. Contact: gimpalibrary@gimpa.edu.gh, info_library@gimpa.edu.gh for Turnitin, phone +233-(0) 501620138. Institute Librarian is Mr. Adolph Agbeh.',
    array['departments', 'library', 'campus facilities', 'study resources', 'turnitin', 'opening hours']
),
(
    'GIMPA-Departments',
    'GIMPA Sports Unit',
    'The GIMPA Sports Unit was established in 2021 under the Office of the Dean of Students to manage sports activities. It is overseen by a Sports Advisory Board chaired by the Dean of Students and a Sports Management Committee headed by the Sports Coordinator. GIMPA has active sports teams including the GIMPA Hockey Queens. Sports activities are open to students, staff, and the wider GIMPA community.',
    array['departments', 'sports', 'athletics', 'hockey', 'student activities', 'recreation']
),
(
    'GIMPA-Departments',
    'Office of International Programmes and Development (OIPD)',
    'The Office of International Programmes and Development handles international admissions and exchange programmes. GIMPA has partnerships with universities abroad - for example, GIMPA Law students can earn a UConn (University of Connecticut) LLM degree through a Ghana-US partnership. International students can contact OIPD at https://www.oipd.gimpa.edu.gh/ for information about international programmes and exchange opportunities.',
    array['departments', 'international programmes', 'oipd', 'international students', 'exchange programmes', 'study abroad']
),
(
    'GIMPA-Departments',
    'GIMPA Training & Consulting (GTC)',
    'GIMPA Training & Consulting arm offers executive and leadership certificate programmes through https://gtc.gimpa.edu.gh/. Short courses include Leadership Development, Strategic Management, Public Financial Management, Human Resource Management, Project Management, Supply Chain Management, and Corporate Governance. These are open to professionals and organizations seeking specialized training and professional development.',
    array['departments', 'training', 'consulting', 'gtc', 'executive education', 'professional development', 'short courses']
),
(
    'GIMPA-Departments',
    'GIMPA Hub for Teaching and Learning (HTL)',
    'The GIMPA Hub for Teaching and Learning is a centre dedicated to fostering innovation, excellence, and inclusivity in education. It supports faculty with teaching practices and provides students with academic support resources. The Head is Dr. Joseph Budu. The HTL runs workshops, provides tools and training, and builds a culture of lifelong learning.',
    array['departments', 'teaching', 'learning', 'htl', 'faculty support', 'academic support', 'innovation']
),
(
    'GIMPA-Departments',
    'Campus Facilities Overview',
    'Key campus facilities on the Greenhill Campus include: Main Administration Block (central hub for administrative offices including Rector office and Registry), Executive Conference Centre (ECC) for conferences and events, Business School building, Faculty of Law building, School of Technology building, Graduate Lecture Block, Greenhill Cafeteria, Hawa Yakubu Hostel, Campus Clinic, and Main Library. These facilities support academic, administrative, and student life activities.',
    array['departments', 'campus facilities', 'buildings', 'administration', 'conference centre', 'cafeteria', 'hostel', 'clinic']
);
